@using sv_c28f8bd4457949928a77298c81aaf138.Models

<div class="step-personal">
    <h4 class="mb-3">Personal Information</h4>

    <div class="mb-3">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="FullName" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
               @bind="Email" @bind:event="oninput" />
        @if (EmailError is not null)
        {
            <div class="invalid-feedback">@EmailError</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Phone" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <textarea class="form-control" rows="2" @bind="Address" @bind:event="oninput"></textarea>
    </div>

    @if (ValidationMessage is not null)
    {
        <div class="alert alert-danger">@ValidationMessage</div>
    }

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ValidationMessage;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ValidationMessage = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ValidationMessage = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            var valid = await ValidateEmail(Email);
            IsValidating = false;

            if (!valid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
        }

        await FullNameChanged.InvokeAsync(FullName);
        await EmailChanged.InvokeAsync(Email);
        await PhoneChanged.InvokeAsync(Phone);
        await AddressChanged.InvokeAsync(Address);
        await OnNext.InvokeAsync();
    }
}

@using sv_c28f8bd4457949928a77298c81aaf138.Models

<div class="step-work-history">
    <h4 class="mb-3">Work History</h4>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        var entry = Entries[index];

        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="card-title mb-0">Position @(index + 1)</h6>
                    @if (Entries.Count > 1)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                    }
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Company"
                               @onchange="e => UpdateEntry(index, entry with { Company = (string?)e.Value ?? \"\" })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Title"
                               @onchange="e => UpdateEntry(index, entry with { Title = (string?)e.Value ?? \"\" })" />
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                               @onchange="e => UpdateEntry(index, entry with { StartDate = ParseDate((string?)e.Value) })" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                               disabled="@(entry.EndDate is null && entry.StartDate != default && IsCurrentJob(index))"
