                                   @onchange="e => ToggleCurrent(index, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="current-@index">Current position</label>
                        </div>
                    </div>
                </div>

                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" value="@entry.Description"
                              @onchange="e => UpdateEntry(index, entry with { Description = (string?)e.Value ?? \"\" })"></textarea>
                </div>
            </div>
        </div>
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        <span class="me-1">+</span> Add Another Position
    </button>

