@using sv_c28f8bd4457949928a77298c81aaf138.Models

<div class="step-work-history">
    <h4 class="mb-3">Work History</h4>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        var entry = Entries[index];

        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="card-title mb-0">Position @(index + 1)</h6>
                    @if (Entries.Count > 1)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                    }
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Company"
                               @onchange="e => UpdateEntry(index, entry with { Company = (string?)e.Value ?? \"\" })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Title"
                               @onchange="e => UpdateEntry(index, entry with { Title = (string?)e.Value ?? \"\" })" />
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                               @onchange="e => UpdateEntry(index, entry with { StartDate = ParseDate((string?)e.Value) })" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                               disabled="@(entry.EndDate is null && entry.StartDate != default && IsCurrentJob(index))"
                               @onchange="e => UpdateEntry(index, entry with { EndDate = ParseNullableDate((string?)e.Value) })" />
                    </div>
                    <div class="col-md-4 d-flex align-items-end">
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="current-@index"
                                   checked="@IsCurrentJob(index)"
                                   @onchange="e => ToggleCurrent(index, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="current-@index">Current position</label>
                        </div>
                    </div>
                </div>

                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" value="@entry.Description"
                              @onchange="e => UpdateEntry(index, entry with { Description = (string?)e.Value ?? \"\" })"></textarea>
                </div>
            </div>
        </div>
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        <span class="me-1">+</span> Add Another Position
    </button>

    @if (ValidationMessage is not null)
    {
        <div class="alert alert-danger">@ValidationMessage</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private HashSet<int> _currentJobs = new();
    private string? ValidationMessage;

    protected override void OnInitialized()
    {
        if (Entries.Count == 0)
            Entries.Add(new WorkEntryModel());

        for (int i = 0; i < Entries.Count; i++)
        {
            if (Entries[i].EndDate is null && Entries[i].Company != "")
                _currentJobs.Add(i);
        }
    }

    private bool IsCurrentJob(int index) => _currentJobs.Contains(index);

    private void ToggleCurrent(int index, bool isCurrent)
    {
        if (isCurrent)
        {
            _currentJobs.Add(index);
            UpdateEntry(index, Entries[index] with { EndDate = null });
        }
        else
        {
            _currentJobs.Remove(index);
        }
    }

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        _currentJobs.Remove(index);
        Entries.RemoveAt(index);
        // Rebuild current jobs set with shifted indices
        var updated = new HashSet<int>();
        foreach (var j in _currentJobs)
            updated.Add(j > index ? j - 1 : j);
        _currentJobs = updated;
    }

    private async Task HandleNext()
    {
        ValidationMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                ValidationMessage = "Company, title, and start date are required for each position.";
                return;
            }
        }

        await EntriesChanged.InvokeAsync(Entries);
        await OnNext.InvokeAsync();
    }

    private string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");
    private string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
    private DateTime ParseDate(string? value) => DateTime.TryParse(value, out var d) ? d : default;
    private DateTime? ParseNullableDate(string? value) => DateTime.TryParse(value, out var d) ? d : null;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public string Description { get; set; } = "";
    }
}

