+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
+                        <input type="text" class="form-control" value="@entry.Title"
+                               @onchange="e => UpdateEntry(index, entry with { Title = (string?)e.Value ?? \"\" })" />
+                    </div>
+                </div>
+
+                <div class="row mb-2">
+                    <div class="col-md-4">
+                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
+                        <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
+                               @onchange="e => UpdateEntry(index, entry with { StartDate = ParseDate((string?)e.Value) })" />
+                    </div>
+                    <div class="col-md-4">
+                        <label class="form-label">End Date</label>
+                        <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
+                               disabled="@(entry.EndDate is null && entry.StartDate != default && IsCurrentJob(index))"
+                               @onchange="e => UpdateEntry(index, entry with { EndDate = ParseNullableDate((string?)e.Value) })" />
+                    </div>
+                    <div class="col-md-4 d-flex align-items-end">
+                        <div class="form-check mb-2">
+                            <input class="form-check-input" type="checkbox" id="current-@index"
+                                   checked="@IsCurrentJob(index)"
+                                   @onchange="e => ToggleCurrent(index, (bool)(e.Value ?? false))" />
+                            <label class="form-check-label" for="current-@index">Current position</label>
+                        </div>
+                    </div>
+                </div>
+
+                <div class="mb-2">
+                    <label class="form-label">Description</label>
+                    <textarea class="form-control" rows="2" value="@entry.Description"
+                              @onchange="e => UpdateEntry(index, entry with { Description = (string?)e.Value ?? \"\" })"></textarea>
+                </div>
+            </div>
+        </div>
+    }
+
+    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
+        <span class="me-1">+</span> Add Another Position
+    </button>
+
