+        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
+    </div>
+</div>
+
+@code {
+    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
+    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
+    [Parameter] public EventCallback OnNext { get; set; }
+    [Parameter] public EventCallback OnBack { get; set; }
+
+    private HashSet<int> _currentJobs = new();
+    private string? ValidationMessage;
+
+    protected override void OnInitialized()
+    {
+        if (Entries.Count == 0)
+            Entries.Add(new WorkEntryModel());
+
+        for (int i = 0; i < Entries.Count; i++)
+        {
+            if (Entries[i].EndDate is null && Entries[i].Company != "")
+                _currentJobs.Add(i);
+        }
+    }
+
+    private bool IsCurrentJob(int index) => _currentJobs.Contains(index);
+
+    private void ToggleCurrent(int index, bool isCurrent)
+    {
+        if (isCurrent)
+        {
+            _currentJobs.Add(index);
+            UpdateEntry(index, Entries[index] with { EndDate = null });
+        }
+        else
+        {
+            _currentJobs.Remove(index);
+        }
+    }
+
+    private void UpdateEntry(int index, WorkEntryModel updated)
+    {
+        Entries[index] = updated;
+    }
+
+    private void AddEntry()
+    {
+        Entries.Add(new WorkEntryModel());
+    }
+
+    private void RemoveEntry(int index)
+    {
+        _currentJobs.Remove(index);
+        Entries.RemoveAt(index);
+        // Rebuild current jobs set with shifted indices
+        var updated = new HashSet<int>();
+        foreach (var j in _currentJobs)
+            updated.Add(j > index ? j - 1 : j);
+        _currentJobs = updated;
+    }
+
+    private async Task HandleNext()
+    {
+        ValidationMessage = null;
+
+        foreach (var entry in Entries)
+        {
+            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
+                || entry.StartDate == default)
+            {
+                ValidationMessage = "Company, title, and start date are required for each position.";
+                return;
+            }
+        }
+
+        await EntriesChanged.InvokeAsync(Entries);
+        await OnNext.InvokeAsync();
+    }
+
+    private string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");
+    private string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
+    private DateTime ParseDate(string? value) => DateTime.TryParse(value, out var d) ? d : default;
+    private DateTime? ParseNullableDate(string? value) => DateTime.TryParse(value, out var d) ? d : null;
+
+    public class WorkEntryModel
+    {
+        public string Company { get; set; } = "";
+        public string Title { get; set; } = "";
+        public DateTime StartDate { get; set; }
+        public DateTime? EndDate { get; set; }
+        public string Description { get; set; } = "";
+    }
+}
