@using sv_c28f8bd4457949928a77298c81aaf138.Models

<div class="step-references">
    <h4 class="mb-3">References</h4>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        var r = References[index];

        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                    @if (References.Count > 2)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                    }
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@r.Name"
                               @onchange="e => UpdateRef(index, r with { Name = (string?)e.Value ?? \"\" })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@r.Relationship"
                               @onchange="e => UpdateRef(index, r with { Relationship = (string?)e.Value ?? \"\" })" />
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" value="@r.Email"
                               @onchange="e => UpdateRef(index, r with { Email = (string?)e.Value ?? \"\" })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" value="@r.Phone"
                               @onchange="e => UpdateRef(index, r with { Phone = (string?)e.Value ?? \"\" })" />
                    </div>
                </div>
            </div>
        </div>
    }

    @if (References.Count < 3)
    {
        <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            <span class="me-1">+</span> Add Reference
        </button>
    }

    @if (ValidationMessage is not null)
    {
        <div class="alert alert-danger">@ValidationMessage</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationMessage;

    protected override void OnInitialized()
    {
        while (References.Count < 2)
            References.Add(new ReferenceModel());
    }

    private void UpdateRef(int index, ReferenceModel updated)
    {
        References[index] = updated;
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ValidationMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ValidationMessage = "All fields are required for each reference.";
                return;
            }
        }

        await ReferencesChanged.InvokeAsync(References);
        await OnNext.InvokeAsync();
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

