@using sv_c28f8bd4457949928a77298c81aaf138.Components.Pages.Apply

<div class="step-review">
    <h4 class="mb-4">Review & Submit</h4>

    @if (Submitted)
    {
        <div class="alert alert-success text-center py-4">
            <h5 class="mb-2">✓ Application Submitted!</h5>
            <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(0)'>Edit</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Address</div>
                </div>
            </div>
        </div>

        <!-- Work History -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 pb-2 border-bottom">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1">@entry.Description</p>
                        }
                    </div>
                }
            </div>
        </div>

        <!-- References -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var r in References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                    </div>
                }
            </div>
        </div>

        <!-- Cover Letter -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@CoverLetter</p>
            </div>
        </div>

        @if (ErrorMessage is not null)
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Submit Application
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<StepWorkHistory.WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<StepReferences.ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public Func<Task<int>>? OnSubmit { get; set; }

    private bool IsSubmitting;
    private bool Submitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        if (OnSubmit is null) return;

        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            ApplicationId = await OnSubmit();
            Submitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

