@page "/apply"
@rendermode InteractiveServer
@using sv_c28f8bd4457949928a77298c81aaf138.Models
@using sv_c28f8bd4457949928a77298c81aaf138.Components.Pages.Apply
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <!-- Step Indicator Bar -->
    <nav class="step-indicator mb-4">
        <div class="d-flex justify-content-between position-relative">
            <div class="step-progress-track"></div>
            @for (int i = 0; i < StepLabels.Length; i++)
            {
                var step = i;
                var state = step < _currentStep ? "completed"
                          : step == _currentStep ? "active"
                          : "upcoming";

                <div class="step-item text-center @state" style="z-index: 1;">
                    <button class="step-circle @state"
                            disabled="@(state == "upcoming")"
                            @onclick="() => GoToStep(step)">
                        @if (state == "completed")
                        {
                            <span>✓</span>
                        }
                        else
                        {
                            <span>@(step + 1)</span>
                        }
                    </button>
                    <div class="step-label mt-1 small">@StepLabels[step]</div>
                </div>
            }
        </div>
    </nav>

    <!-- Step Content -->
    <div class="step-content">
        @switch (_currentStep)
        {
            case 0:
                <StepPersonalInfo
                    FullName="@_fullName" FullNameChanged="v => _fullName = v"
                    Email="@_email" EmailChanged="v => _email = v"
                    Phone="@_phone" PhoneChanged="v => _phone = v"
                    Address="@_address" AddressChanged="v => _address = v"
                    ValidateEmail="ApplicationService.ValidateEmailAsync"
                    OnNext="NextStep" />
                break;
            case 1:
                <StepWorkHistory
                    Entries="@_workEntries" EntriesChanged="v => _workEntries = v"
                    OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 2:
                <StepReferences
                    References="@_references" ReferencesChanged="v => _references = v"
                    OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <StepCoverLetter
                    CoverLetter="@_coverLetter" CoverLetterChanged="v => _coverLetter = v"
                    OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <StepReview
                    FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                    WorkEntries="@_workEntries" References="@_references"
                    CoverLetter="@_coverLetter"
                    OnEditStep="GoToStep" OnBack="PrevStep"
                    OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

<style>
    .step-indicator .d-flex {
        gap: 0;
    }

    .step-item {
        flex: 1;
        display: flex;
        flex-direction: column;
        align-items: center;
    }

    .step-progress-track {
        position: absolute;
        top: 18px;
        left: 10%;
        right: 10%;
        height: 3px;
        background: #dee2e6;
        z-index: 0;
    }

    .step-circle {
        width: 36px;
        height: 36px;
        border-radius: 50%;
        border: 2px solid #dee2e6;
        background: #fff;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: 600;
        font-size: 0.85rem;
        cursor: default;
        transition: all 0.2s;
    }

    .step-circle.active {
        border-color: #0d6efd;
        background: #0d6efd;
        color: #fff;
    }

    .step-circle.completed {
        border-color: #198754;
        background: #198754;
        color: #fff;
        cursor: pointer;
    }

    .step-circle.upcoming {
        color: #adb5bd;
    }

    .step-label {
        font-size: 0.75rem;
        color: #6c757d;
    }

    .step-item.active .step-label {
        color: #0d6efd;
        font-weight: 600;
    }

    .step-item.completed .step-label {
        color: #198754;
    }
</style>

@code {
    private static readonly string[] StepLabels =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private int _currentStep;
    private int _maxCompletedStep = -1;

    // Step 1 state
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 state
    private List<StepWorkHistory.WorkEntryModel> _workEntries = new() { new() };

    // Step 3 state
    private List<StepReferences.ReferenceModel> _references = new() { new(), new() };

    // Step 4 state
    private string _coverLetter = "";

    private void NextStep()
    {
        if (_currentStep > _maxCompletedStep)
            _maxCompletedStep = _currentStep;

        if (_currentStep < StepLabels.Length - 1)
            _currentStep++;
    }

    private void PrevStep()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private void GoToStep(int step)
    {
        if (step <= _maxCompletedStep)
            _currentStep = step;
    }

    private async Task<int> SubmitApplication()
    {
        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
        var workHistory = new WorkHistory(
            _workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList());
        var references = _references.Select(r =>
            new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
        var application = new JobApplication(personal, workHistory, references, _coverLetter);

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

