+
+    .step-progress-track {
+        position: absolute;
+        top: 18px;
+        left: 10%;
+        right: 10%;
+        height: 3px;
+        background: #dee2e6;
+        z-index: 0;
+    }
+
+    .step-circle {
+        width: 36px;
+        height: 36px;
+        border-radius: 50%;
+        border: 2px solid #dee2e6;
+        background: #fff;
+        display: flex;
+        align-items: center;
+        justify-content: center;
+        font-weight: 600;
+        font-size: 0.85rem;
+        cursor: default;
+        transition: all 0.2s;
+    }
+
+    .step-circle.active {
+        border-color: #0d6efd;
+        background: #0d6efd;
+        color: #fff;
+    }
+
+    .step-circle.completed {
+        border-color: #198754;
+        background: #198754;
+        color: #fff;
+        cursor: pointer;
+    }
+
+    .step-circle.upcoming {
+        color: #adb5bd;
+    }
+
+    .step-label {
+        font-size: 0.75rem;
+        color: #6c757d;
+    }
+
+    .step-item.active .step-label {
+        color: #0d6efd;
