+        color: #198754;
+    }
+</style>
+
+@code {
+    private static readonly string[] StepLabels =
+    {
+        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
+    };
+
+    private int _currentStep;
+    private int _maxCompletedStep = -1;
+
+    // Step 1 state
+    private string _fullName = "";
+    private string _email = "";
+    private string _phone = "";
+    private string _address = "";
+
+    // Step 2 state
+    private List<StepWorkHistory.WorkEntryModel> _workEntries = new() { new() };
+
+    // Step 3 state
+    private List<StepReferences.ReferenceModel> _references = new() { new(), new() };
+
+    // Step 4 state
+    private string _coverLetter = "";
+
+    private void NextStep()
+    {
+        if (_currentStep > _maxCompletedStep)
+            _maxCompletedStep = _currentStep;
+
+        if (_currentStep < StepLabels.Length - 1)
+            _currentStep++;
+    }
+
+    private void PrevStep()
+    {
+        if (_currentStep > 0)
+            _currentStep--;
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step <= _maxCompletedStep)
+            _currentStep = step;
+    }
+
+    private async Task<int> SubmitApplication()
+    {
+        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
+        var workHistory = new WorkHistory(
+            _workEntries.Select(e =>
+                new WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList());
+        var references = _references.Select(r =>
+            new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
+        var application = new JobApplication(personal, workHistory, references, _coverLetter);
+
+        return await ApplicationService.SubmitApplicationAsync(application);
+    }
+}
